/* ===============================================  LPSPI CFG1 MCFG [16..18]  =============================================== */
                                  /* LPSPI_CFG1_MCFG                                                          */
#define LPSPI_CFG1_MCFG_000                   0U      /* 000 : Match is disabled.                                           */
#define LPSPI_CFG1_MCFG_010                   2U      /* 010 : 010b - Match is enabled  if 1st data word equals MATCH0
                                                     OR MATCH1  i.e.  (1st data word = MATCH0 + MATCH1)                        */
#define LPSPI_CFG1_MCFG_011                   3U      /* 011 : 011b - Match is enabled  if any data word equals MATCH0
                                                     OR MATCH1  i.e.  (any data word = MATCH0 + MATCH1)                        */
#define LPSPI_CFG1_MCFG_100                   4U      /* 100 : 100b - Match is enabled  if 1st data word equals MATCH0
                                                     AND 2nd data word equals MATCH1  i.e.  [(1st data word
                                                     = MATCH0) * (2nd data word = MATCH1)]                                     */
#define LPSPI_CFG1_MCFG_101                   5U      /* 101 : 101b - Match is enabled  if any data word equals MATCH0
                                                     AND the next data word equals MATCH1  i.e.  [(any data
                                                     word = MATCH0) * (next data word = MATCH1)]                               */
#define LPSPI_CFG1_MCFG_110                   6U      /* 110 : 110b - Match is enabled  if(1st data word AND MATCH1)
                                                     equals (MATCH0 AND MATCH1)  i.e.  [(1st data word * MATCH1)
                                                     = (MATCH0 * MATCH1)]                                                      */
#define LPSPI_CFG1_MCFG_111                   7U      /* 111 : 111b - Match is enabled  if(any data word AND MATCH1)
                                                     equals (MATCH0 AND MATCH1)  i.e.  [(any data word * MATCH1)
                                                     = (MATCH0 * MATCH1)]                                                      */

