#define LPSPI_CFG1_IOPCFG_10                  2U      /* 10 : SOUT is used for both input and output data.                  */
#define LPSPI_CFG1_IOPCFG_11                  3U      /* 11 : SOUT is used for input data and SIN for output data.          */

