                                  /* LPUART_DATA_RXIDLE                                                */
#define LPUART_DATA_RXIDLE_0                  0U      /* 0 : Receiver was not idle before receiving this character.         */
#define LPUART_DATA_RXIDLE_1                  1U      /* 1 : Receiver was idle before receiving this character.             */


