                                  /* LPUART_DATA_FETXSC                                                */
#define LPUART_DATA_FETXSC_0                  0U      /* 0 : The dataword was received without a frame error on read
                                                     or transmit a normal character on write.                           */
#define LPUART_DATA_FETXSC_1                  1U      /* 1 : The dataword was received with a frame error  or transmit
                                                     an idle or break character on transmit.                            */


