                                  /* LPUART_DATA_PE                                                    */
#define LPUART_DATA_PE_0                      0U      /* 0 : The dataword was received without a parity error.              */
#define LPUART_DATA_PE_1                      1U      /* 1 : The dataword was received with a parity error.                 */


