                                  /* LPUART_DATA_NE                                                    */
#define LPUART_DATA_NE_0                      0U      /* 0 : The dataword was received without noise.                       */
#define LPUART_DATA_NE_1                      1U      /* 1 : The data was received with noise.                              */


