/* ==========================================================  MIR  ========================================================== */
/* ===============================================  LPUART MIR TXCSEN [0..0]  =============================================== */
                                  /* LPUART_MIR_TXCSEN                                                 */
#define LPUART_MIR_TXCSEN_0                   0U      /* 0 : CTS has no effect on the transmitter.                          */
#define LPUART_MIR_TXCSEN_1                   1U      /* 1 : Enables clear-to-send operation. The transmitter checks
                                                     the state of CTS each time it is ready to send a character.
                                                     If CTS is asserted  the character is sent. If CTS is deasserted
                                                     the signal TXD remains in the mark state and transmission
                                                     is delayed until CTS is asserted. Changes in CTS as a character
                                                     is being sent do not affect its transmission.                      */


/* ===============================================  LPUART MIR TXRSEN [1..1]  =============================================== */
                                  /* LPUART_MIR_TXRSEN                                                 */
#define LPUART_MIR_TXRSEN_0                   0U      /* 0 : The transmitter has no effect on RTS.                          */
#define LPUART_MIR_TXRSEN_1                   1U      /* 1 : When a character is placed into an empty transmitter data
                                                     buffer   RTS asserts one bit time before the start bit
                                                     is transmitted. RTS deasserts one bit time after all characters
                                                     in the transmitter data buffer and shift register are completely
                                                     sent  including the last stop bit.                                 */


/* ==============================================  LPUART MIR TXRSPCFG [2..2]  ============================================== */
                                  /* LPUART_MIR_TXRSPCFG                                               */
#define LPUART_MIR_TXRSPCFG_0                 0U      /* 0 : Transmitter RTS is active low.                                 */
#define LPUART_MIR_TXRSPCFG_1                 1U      /* 1 : Transmitter RTS is active high.                                */


/* ===============================================  LPUART MIR RXRSEN [3..3]  =============================================== */
                                  /* LPUART_MIR_RXRSEN                                                 */
#define LPUART_MIR_RXRSEN_0                   0U      /* 0 : The receiver has no effect on RTS.                             */


