#define LPUART_MIR_TXCSCFG_1                  1U      /* 1 : CTS input is sampled when the transmitter is idle.             */


/* =============================================  LPUART MIR TXCSRCSEL [5..5]  ============================================== */
                                  /* LPUART_MIR_TXCSRCSEL                                              */
#define LPUART_MIR_TXCSRCSEL_0                0U      /* 0 : CTS input is the CTS_B pin.                                    */
#define LPUART_MIR_TXCSRCSEL_1                1U      /* 1 : CTS input is the inverted Receiver Match result.               */


