#define LPUART_FIFO_TXFBDCFG_010              2U      /* 010 : Transmit FIFO/Buffer depth = 8 datawords.                    */
#define LPUART_FIFO_TXFBDCFG_011              3U      /* 011 : Transmit FIFO/Buffer depth = 16 datawords.                   */
#define LPUART_FIFO_TXFBDCFG_100              4U      /* 100 : Transmit FIFO/Buffer depth = 32 datawords.                   */
#define LPUART_FIFO_TXFBDCFG_101              5U      /* 101 : Transmit FIFO/Buffer depth = 64 datawords.                   */
#define LPUART_FIFO_TXFBDCFG_110              6U      /* 110 : Transmit FIFO/Buffer depth = 128 datawords.                  */
#define LPUART_FIFO_TXFBDCFG_111              7U      /* 111 : Transmit FIFO/Buffer depth = 256 datawords                   */


