/* =========================================================  CTRL0  ========================================================= */
/* ===============================================  COMP CTRL0 HBHLSEL [0..1]  =============================================== */
                                   /* COMP_CTRL0_HBHLSEL                                                 */
#define COMP_CTRL0_HBHLSEL_00                  0U      /* 00 : The hard block output has level 0 hysteresis internally.      */
