#define COMP_CTRL0_HBHLSEL_10                  2U      /* 10 : The hard block output has level 2 hysteresis internally.      */
#define COMP_CTRL0_HBHLSEL_11                  3U      /* 11 : The hard block output has level 3 hysteresis internally.      */


