                                  /* COMP_CTRL0_HBOLSEL                                                 */
#define COMP_CTRL0_HBOLSEL_0                   0U      /* 0 : The comparator hard block output has level 0 offset internally.*/
#define COMP_CTRL0_HBOLSEL_1                   1U      /* 1 : The comparator hard block output has level 1 offset internally.*/


/* ==============================================  COMP CTRL0 FOSMPCNT [4..6]  =============================================== */
                               /* COMP_CTRL0_FOSMPCNT                                                */
#define COMP_CTRL0_FOSMPCNT_000                0U      /* 000 : Filter is disabled. If SE = 1  then COUT is a logic zero
                                                     (this is not a legal state  and is not recommended). If
                                                     SE = 0  COUT = COUTA.                                              */
#define COMP_CTRL0_FOSMPCNT_001                1U      /* 001 : 1 consecutive sample must agree (comparator output is
                                                     simply sampled).                                                   */
#define COMP_CTRL0_FOSMPCNT_010                2U      /* 010 : 2 consecutive samples must agree.                            */
#define COMP_CTRL0_FOSMPCNT_011                3U      /* 011 : 3 consecutive samples must agree.                            */
#define COMP_CTRL0_FOSMPCNT_100                4U      /* 100 : 4 consecutive samples must agree.                            */
#define COMP_CTRL0_FOSMPCNT_101                5U      /* 101 : 5 consecutive samples must agree.                            */
#define COMP_CTRL0_FOSMPCNT_110                6U      /* 110 : 6 consecutive samples must agree.                            */
#define COMP_CTRL0_FOSMPCNT_111                7U      /* 111 : 7 consecutive samples must agree.                            */


/* ================================================  COMP CTRL0 ACEN [8..8]  ================================================= */
                                  /* COMP_CTRL0_ACEN                                                    */
#define COMP_CTRL0_ACEN_0                      0U      /* 0 : Analog Comparator is disabled.                                 */
#define COMP_CTRL0_ACEN_1                      1U      /* 1 : Analog Comparator is enabled.                                  */


/* ===============================================  COMP CTRL0 COPCFG [9..9]  ================================================ */
                               /* COMP_CTRL0_COPCFG                                                  */
#define COMP_CTRL0_COPCFG_0                    0U      /* 0 : When OPE is 0  the comparator output (after window/filter
                                                     settings dependent on software configuration) is not available
                                                     to a packaged pin.                                                 */
#define COMP_CTRL0_COPCFG_1                    1U      /* 1 : When OPE is 1  and if the software has configured the comparator
                                                     to own a packaged pin  the comparator is available in a
                                                     packaged pin.                                                      */


/* ===============================================  COMP CTRL0 COCFG [10..10]  =============================================== */
                                 /* COMP_CTRL0_COCFG                                                   */
#define COMP_CTRL0_COCFG_0                     0U      /* 0 : Set CMPO to equal COUT (filtered comparator output).           */
#define COMP_CTRL0_COCFG_1                     1U      /* 1 : Set CMPO to equal COUTA (unfiltered comparator output).        */


/* ===============================================  COMP CTRL0 INVEN [11..11]  =============================================== */
                                 /* COMP_CTRL0_INVEN                                                   */
#define COMP_CTRL0_INVEN_0                     0U      /* 0 : Does not invert the comparator output.                         */
#define COMP_CTRL0_INVEN_1                     1U      /* 1 : Inverts the comparator output.                                 */


/* ===============================================  COMP CTRL0 PMSEL [12..12]  =============================================== */
                                 /* COMP_CTRL0_PMSEL                                                   */
#define COMP_CTRL0_PMSEL_0                     0U      /* 0 : Low Speed (LS) comparison mode is selected.                    */
#define COMP_CTRL0_PMSEL_1                     1U      /* 1 : High Speed (HS) comparison mode is selected  in VLPx mode
                                                     or Stop mode switched to Low Speed (LS) mode.                      */


/* ==============================================  COMP CTRL0 WINMEN [14..14]  =============================================== */
