#define APM32_SCB_CFSR_MMARVALID_0               0U      /* 0 : value in MMAR is not a valid fault address                     */
#define APM32_SCB_CFSR_MMARVALID_1               1U      /* 1 : MMAR holds a valid fault address                               */


/* ==============================================  APM32_SCB CFSR IBUSERR [8..8]  ============================================== */
                                  /* APM32_SCB_CFSR_IBUSERR                                               */
#define APM32_SCB_CFSR_IBUSERR_0                 0U      /* 0 : no instruction bus error                                       */
#define APM32_SCB_CFSR_IBUSERR_1                 1U      /* 1 : instruction bus error                                          */


/* =============================================  APM32_SCB CFSR PRECISERR [9..9]  ============================================= */
                                   /* APM32_SCB_CFSR_PRECISERR                                             */
#define APM32_SCB_CFSR_PRECISERR_0               0U      /* 0 : no precise data bus error                                      */
#define APM32_SCB_CFSR_PRECISERR_1               1U      /* 1 : a data bus error has occurred  and the PC value stacked
                                                     for the exception return points to the instruction that
                                                     caused the fault                                                   */


/* ===========================================  APM32_SCB CFSR IMPRECISERR [10..10]  =========================================== */
                                  /* APM32_SCB_CFSR_IMPRECISERR                                           */
#define APM32_SCB_CFSR_IMPRECISERR_0             0U      /* 0 : no imprecise data bus error                                    */
#define APM32_SCB_CFSR_IMPRECISERR_1             1U      /* 1 : a data bus error has occurred  but the return address in
                                                     the stack frame is not related to the instruction that
                                                     caused the error                                                   */


/* ============================================  APM32_SCB CFSR UNSTKERR [11..11]  ============================================= */
                                  /* APM32_SCB_CFSR_UNSTKERR                                              */
#define APM32_SCB_CFSR_UNSTKERR_0                0U      /* 0 : no unstacking fault                                            */
#define APM32_SCB_CFSR_UNSTKERR_1                1U     /* 1 : unstack for an exception return has caused one or more BusFaults*/


/* =============================================  APM32_SCB CFSR STKERR [12..12]  ============================================== */
                                   /* APM32_SCB_CFSR_STKERR                                                */
#define APM32_SCB_CFSR_STKERR_0                  0U      /* 0 : no stacking fault                                              */
#define APM32_SCB_CFSR_STKERR_1                  1U     /* 1 : stacking for an exception entry has caused one or more BusFaults*/


/* =============================================  APM32_SCB CFSR LSPERR [13..13]  ============================================== */
                                   /* APM32_SCB_CFSR_LSPERR                                                */
#define APM32_SCB_CFSR_LSPERR_0                  0U  /* 0 : No bus fault occurred during floating-point lazy state preservation*/
#define APM32_SCB_CFSR_LSPERR_1                  1U  /* 1 : A bus fault occurred during floating-point lazy state preservation */


/* ============================================  APM32_SCB CFSR BFARVALID [15..15]  ============================================ */
                                  /* APM32_SCB_CFSR_BFARVALID                                             */
#define APM32_SCB_CFSR_BFARVALID_0               0      /* 0 : value in BFAR is not a valid fault address                      */
#define APM32_SCB_CFSR_BFARVALID_1               1      /* 1 : BFAR holds a valid fault address                                */


/* ===========================================  APM32_SCB CFSR UNDEFINSTR [16..16]  ============================================ */
                                   /* APM32_SCB_CFSR_UNDEFINSTR                                            */
#define APM32_SCB_CFSR_UNDEFINSTR_0               0U     /* 0 : no undefined instruction UsageFault                            */
#define APM32_SCB_CFSR_UNDEFINSTR_1               1U     /* 1 : the processor has attempted to execute an undefined instruction*/


/* ============================================  APM32_SCB CFSR INVSTATE [17..17]  ============================================= */
                                  /* APM32_SCB_CFSR_INVSTATE                                              */
#define APM32_SCB_CFSR_INVSTATE_0                 0U     /* 0 : no invalid state UsageFault                                    */
#define APM32_SCB_CFSR_INVSTATE_1                 1U     /* 1 : the processor has attempted to execute an instruction that
                                                     makes illegal use of the EPSR                                      */


/* ==============================================  APM32_SCB CFSR INVPC [18..18]  ============================================== */
                                  /* APM32_SCB_CFSR_INVPC                                                 */
#define APM32_SCB_CFSR_INVPC_0                    0U     /* 0 : no invalid PC load UsageFault                                  */
#define APM32_SCB_CFSR_INVPC_1                    1U      /* 1 : the processor has attempted an illegal load of EXC_RETURN
                                                     to the PC                                                          */


/* ==============================================  APM32_SCB CFSR NOCP [19..19]  =============================================== */
                                   /* APM32_SCB_CFSR_NOCP                                                  */
#define APM32_SCB_CFSR_NOCP_0                     0U     /* 0 : no UsageFault caused by attempting to access a coprocessor     */
#define APM32_SCB_CFSR_NOCP_1                     1U     /* 1 : the processor has attempted to access a coprocessor            */


/* ============================================  APM32_SCB CFSR UNALIGNED [24..24]  ============================================ */
                                  /* APM32_SCB_CFSR_UNALIGNED                                             */
#define APM32_SCB_CFSR_UNALIGNED_0                0U      /* 0 : no unaligned access fault  or unaligned access trapping
                                                     not enabled                                                        */
#define APM32_SCB_CFSR_UNALIGNED_1                1U     /* 1 : the processor has made an unaligned memory access              */


/* ============================================  APM32_SCB CFSR DIVBYZERO [25..25]  ============================================ */
                                   /* APM32_SCB_CFSR_DIVBYZERO                                             */
#define APM32_SCB_CFSR_DIVBYZERO_0                0U      /* 0 : no divide by zero fault  or divide by zero trapping not
                                                     enabled                                                            */
#define APM32_SCB_CFSR_DIVBYZERO_1                1U      /* 1 : the processor has executed an SDIV or UDIV instruction with
                                                     a divisor of 0                                                     */


/* =========================================================  HFSR  ========================================================== */
/* ==============================================  APM32_SCB HFSR VECTTBL [1..1]  ============================================== */
                                   /* APM32_SCB_HFSR_VECTTBL                                               */
#define APM32_SCB_HFSR_VECTTBL_0                  0U     /* 0 : no BusFault on vector table read                               */
#define APM32_SCB_HFSR_VECTTBL_1                  1U     /* 1 : BusFault on vector table read                                  */


/* =============================================  APM32_SCB HFSR FORCED [30..30]  ============================================== */
                                  /* APM32_SCB_HFSR_FORCED                                                */
#define APM32_SCB_HFSR_FORCED_0                   0U     /* 0 : no forced HardFault                                            */
#define APM32_SCB_HFSR_FORCED_1                   1U     /* 1 : forced HardFault                                               */


/* =========================================================  DFSR  ========================================================== */
/* ==============================================  APM32_SCB DFSR HALTED [0..0]  =============================================== */
                                  /* APM32_SCB_DFSR_HALTED                                                */
#define APM32_SCB_DFSR_HALTED_0                   0U     /* 0 : No active halt request debug event                             */
#define APM32_SCB_DFSR_HALTED_1                   1U     /* 1 : Halt request debug event active                                */


/* ===============================================  APM32_SCB DFSR BKPT [1..1]  ================================================ */
                                  /* APM32_SCB_DFSR_BKPT                                                  */
#define APM32_SCB_DFSR_BKPT_0                     0U     /* 0 : No current breakpoint debug event                              */
#define APM32_SCB_DFSR_BKPT_1                     1U     /* 1 : At least one current breakpoint debug event                    */


/* ==============================================  APM32_SCB DFSR DWTTRAP [2..2]  ============================================== */
                                   /* APM32_SCB_DFSR_DWTTRAP                                               */
#define APM32_SCB_DFSR_DWTTRAP_0                  0U      /* 0 : No current debug events generated by the DWT                  */
#define APM32_SCB_DFSR_DWTTRAP_1                  1U      /* 1 : At least one current debug event generated by the DWT         */


/* ==============================================  APM32_SCB DFSR VCATCH [3..3]  =============================================== */
                                  /* APM32_SCB_DFSR_VCATCH                                                       */
#define APM32_SCB_DFSR_VCATCH_0                   0U      /* 0 : No Vector catch triggered                                     */
#define APM32_SCB_DFSR_VCATCH_1                   1U      /* 1 : Vector catch triggered                                         */


/* =============================================  APM32_SCB DFSR EXTERNAL [4..4]  ============================================== */
                                   /* APM32_SCB_DFSR_EXTERNAL                                              */
#define APM32_SCB_DFSR_EXTERNAL_0                 0U      /* 0 : No EDBGRQ debug event                                          */
#define APM32_SCB_DFSR_EXTERNAL_1                 1U      /* 1 : EDBGRQ debug event                                             */


/* =========================================================  MMFAR  ========================================================= */
/* =========================================================  BFAR  ========================================================== */
/* =========================================================  AFSR  ========================================================== */
/* =========================================================  CPACR  ========================================================= */
/* ==============================================  APM32_SCB CPACR CP10 [20..21]  ============================================== */
                                   /* APM32_SCB_CPACR_CP10                                                 */
#define APM32_SCB_CPACR_CP10_00                   0U    /* 00 : Access denied. Any attempted access generates a NOCP UsageFault*/
#define APM32_SCB_CPACR_CP10_01                   1U      /* 01 : Privileged access only. An unprivileged access generates
                                                     a NOCP fault.                                                      */
#define APM32_SCB_CPACR_CP10_10                   2U      /* 10 : Reserved. The result of any access is UNPREDICTABLE.          */
#define APM32_SCB_CPACR_CP10_11                   3U      /* 11 : Full access.                                                  */
 /* ==============================================  APM32_SCB CPACR CP11 [22..23]  ============================================== */
                                  /* APM32_SCB_CPACR_CP11                                                 */
#define APM32_SCB_CPACR_CP11_00                   0U   /* 00 : Access denied. Any attempted access generates a NOCP UsageFault  */
#define APM32_SCB_CPACR_CP11_01                   1U      /* 01 : Privileged access only. An unprivileged access generates
                                                     a NOCP fault.                                                      */
#define APM32_SCB_CPACR_CP11_10                   2U      /* 10 : Reserved. The result of any access is UNPREDICTABLE.          */
#define APM32_SCB_CPACR_CP11_11                   3U      /* 11 : Full access.                                                  */


/* =========================================================  FPCCR  ========================================================= */
/* ==============================================  APM32_SCB FPCCR LSPACT [0..0]  ============================================== */
                                 /* APM32_SCB_FPCCR_LSPACT                                               */
#define APM32_SCB_FPCCR_LSPACT_0                  0U      /* 0 : Lazy state preservation is not active.                         */
#define APM32_SCB_FPCCR_LSPACT_1                  1U      /* 1 : Lazy state preservation is active. floating-point stack
                                                     frame has been allocated but saving state to it has been
                                                     deferred.                                                                 */


/* ===============================================  APM32_SCB FPCCR USER [1..1]  =============================================== */
                                  /* APM32_SCB_FPCCR_USER                                                        */
#define APM32_SCB_FPCCR_USER_0                    0U      /* 0 : Privilege level was not user when the floating-point stack
                                                     frame was allocated.                                                      */
#define APM32_SCB_FPCCR_USER_1                    1U      /* 1 : Privilege level was user when the floating-point stack frame
                                                     was allocated.                                                            */


/* ==============================================  APM32_SCB FPCCR THREAD [3..3]  ============================================== */
                                  /* APM32_SCB_FPCCR_THREAD                                                      */
#define APM32_SCB_FPCCR_THREAD_0                  0U      /* 0 : Mode was not Thread Mode when the floating-point stack frame
                                                     was allocated.                                                            */
#define APM32_SCB_FPCCR_THREAD_1                  1U      /* 1 : Mode was Thread Mode when the floating-point stack frame
                                                     was allocated.                                                            */


/* ==============================================  APM32_SCB FPCCR HFRDY [4..4]  =============================================== */
                                  /* APM32_SCB_FPCCR_HFRDY                                                       */
#define APM32_SCB_FPCCR_HFRDY_0                   0U      /* 0 : Priority did not permit setting the HardFault handler to
                                                     the pending state when the floating-point stack frame was
                                                     allocated.                                                                */
#define APM32_SCB_FPCCR_HFRDY_1                   1U      /* 1 : Priority permitted setting the HardFault handler to the
                                                     pending state when the floating-point stack frame was allocated.          */


/* ==============================================  APM32_SCB FPCCR MMRDY [5..5]  =============================================== */
                                /* APM32_SCB_FPCCR_MMRDY                                                       */
#define APM32_SCB_FPCCR_MMRDY_0                   0U      /* 0 : MemManage is disabled or priority did not permit setting
                                                     the MemManage handler to the pending state when the floating-point
                                                     stack frame was allocated.                                                */
#define APM32_SCB_FPCCR_MMRDY_1                   1U      /* 1 : MemManage is enabled and priority permitted setting the
                                                     MemManage handler to the pending state when the floating-point
                                                     stack frame was allocated.                                                */


/* ==============================================  APM32_SCB FPCCR BFRDY [6..6]  =============================================== */
                                  /* APM32_SCB_FPCCR_BFRDY                                                       */
#define APM32_SCB_FPCCR_BFRDY_0                   0U      /* 0 : BusFault is disabled or priority did not permit setting
                                                     the BusFault handler to the pending state when the floating-point
                                                     stack frame was allocated.                                                */
#define APM32_SCB_FPCCR_BFRDY_1                   1U      /* 1 : BusFault is disabled or priority did not permit setting
                                                     the BusFault handler to the pending state when the floating-point
                                                     stack frame was allocated.                                                */


/* ==============================================  APM32_SCB FPCCR MONRDY [8..8]  ============================================== */
                                   /* APM32_SCB_FPCCR_MONRDY                                                      */
#define APM32_SCB_FPCCR_MONRDY_0                  0U      /* 0 : DebugMonitor is disabled or priority did not permit setting
                                                     MON_PEND when the floating-point stack frame was allocated.               */
#define APM32_SCB_FPCCR_MONRDY_1                  1U      /* 1 : DebugMonitor is enabled and priority permits setting MON_PEND
                                                     when the floating-point stack frame was allocated.                        */


/* =============================================  APM32_SCB FPCCR LSPEN [30..30]  ============================================== */
                                  /* APM32_SCB_FPCCR_LSPEN                                                       */
#define APM32_SCB_FPCCR_LSPEN_0                   0U      /* 0 : Disable automatic lazy state preservation for floating-point
                                                     context.                                                                  */
#define APM32_SCB_FPCCR_LSPEN_1                   1U      /* 1 : Enable automatic lazy state preservation for floating-point
                                                     context.                                                                  */


/* =============================================  APM32_SCB FPCCR ASPEN [31..31]  ============================================== */
                                  /* APM32_SCB_FPCCR_ASPEN                                                       */
#define APM32_SCB_FPCCR_ASPEN_0                   0U      /* 0 : Disable CONTROL2 setting on execution of a floating-point
                                                     instruction.                                                              */
#define APM32_SCB_FPCCR_ASPEN_1                   1U      /* 1 : Enable CONTROL2 setting on execution of a floating-point
                                                     instruction.                                                              */


/* =========================================================  FPCAR  ========================================================= */
/* ========================================================  FPDSCR  ========================================================= */
/* =============================================  APM32_SCB FPDSCR RMode [22..23]  ============================================= */
                                 /* APM32_SCB_FPDSCR_RMode                                                      */
#define APM32_SCB_FPDSCR_RMode_00                 0U      /* 00 : Round to Nearest (RN) mode                                    */
#define APM32_SCB_FPDSCR_RMode_01                 1U      /* 01 : Round towards Plus Infinity (RP) mode.                        */
#define APM32_SCB_FPDSCR_RMode_10                 2U      /* 10 : Round towards Minus Infinity (RM) mode.                       */
#define APM32_SCB_FPDSCR_RMode_11                 3U      /* 11 : Round towards Zero (RZ) mode.                                 */


/* ==============================================  APM32_SCB FPDSCR FZ [24..24]  =============================================== */
                                  /* APM32_SCB_FPDSCR_FZ                                                  */
#define APM32_SCB_FPDSCR_FZ_0                    0U      /* 0 : Flush-to-zero mode disabled. Behavior of the floating-point
                                                     system is fully compliant with the IEEE 754 standard.              */
#define APM32_SCB_FPDSCR_FZ_1                    1U      /* 1 : Flush-to-zero mode enabled.                                    */


/* ==============================================  APM32_SCB FPDSCR DN [25..25]  =============================================== */
                                   /* APM32_SCB_FPDSCR_DN                                                  */
#define APM32_SCB_FPDSCR_DN_0                    0U      /* 0 : NaN operands propagate through to the output of a floating-point
                                                     operation.                                                         */
#define APM32_SCB_FPDSCR_DN_1                    1U      /* 1 : Any operation involving one or more NaNs returns the Default
                                                     NaN.                                                               */


/* ==============================================  APM32_SCB FPDSCR AHP [26..26]  ============================================== */
                                 /* APM32_SCB_FPDSCR_AHP                                                 */
#define APM32_SCB_FPDSCR_AHP_0                   0U      /* 0 : IEEE half-precision format selected.                           */
#define APM32_SCB_FPDSCR_AHP_1                   1U      /* 1 : Alternative half-precision format selected.                    */




