/* ========================================================  SINCSTS  ======================================================== */
/* ===============================================  MC SINCSTS SINCFLG [0..7]  =============================================== */
                                  /* MC_SINCSTS_SINCFLG                                                 */
#define MC_SINCSTS_SINCFLG_0                    0U      /* 0 : A bus slave connection to AXBS input port n is absent          */
#define MC_SINCSTS_SINCFLG_1                    1U      /* 1 : A bus slave connection to AXBS input port n is present         */


/* ========================================================  MINCSTS  ======================================================== */
/* ===============================================  MC MINCSTS MINCFLG [0..7]  =============================================== */
                                  /* MC_MINCSTS_MINCFLG                                                 */
#define MC_MINCSTS_MINCFLG_0                    0U      /* 0 : A bus master connection to AXBS input port n is absent         */
#define MC_MINCSTS_MINCFLG_1                    1U      /* 1 : A bus master connection to AXBS input port n is present        */


/* ========================================================  CPCTRL  ========================================================= */
/* ================================================  MC CPCTRL HMSTS [0..1]  ================================================= */
                                 /* MC_CPCTRL_HMSTS                                                    */
#define MC_CPCTRL_HMSTS_00                     0U      /* 00 : Waiting for request                                           */
#define MC_CPCTRL_HMSTS_01                     1U      /* 01 : Waiting for platform idle                                     */
#define MC_CPCTRL_HMSTS_11                     3U      /* 11 : Platform stalled                                              */
#define MC_CPCTRL_HMSTS_10                     2U      /* 10 : Unused state                                                  */


/* ==============================================  MC CPCTRL RXHREQFLG [2..2]  =============================================== */
                                  /* MC_CPCTRL_RXHREQFLG                                                */
#define MC_CPCTRL_RXHREQFLG_0                  0U      /* 0 : AXBS is not receiving halt request                             */
#define MC_CPCTRL_RXHREQFLG_1                  1U      /* 1 : AXBS is receiving halt request                                 */

/* =================================================  MC CPCTRL HSTS [3..3]  ================================================= */
                                  /* MC_CPCTRL_HSTS                                                     */
#define MC_CPCTRL_HSTS_0                       0U      /* 0 : AXBS is not currently halted                                   */
#define MC_CPCTRL_HSTS_1                       1U      /* 1 : AXBS is currently halted                                       */


/* ==============================================  MC CPCTRL FMCPGISTS [4..4]  =============================================== */
                                  /* MC_CPCTRL_FMCPGISTS                                                */
#define MC_CPCTRL_FMCPGISTS_0                  0U      /* 0 : FMC program flash is not idle                                  */
#define MC_CPCTRL_FMCPGISTS_1                  1U      /* 1 : FMC program flash is currently idle                            */


/* ===============================================  MC CPCTRL ACISTS [6..6]  =============================================== */
                                  /* MC_CPCTRL_ACISTS                                                 */
#define MC_CPCTRL_ACISTS_0                   0U      /* 0 : PBRIDGE is not idle                                            */
#define MC_CPCTRL_ACISTS_1                   1U      /* 1 : PBRIDGE is currently idle                                      */


/* ================================================  MC CPCTRL CASEL [9..9]  ================================================= */
                                  /* MC_CPCTRL_CASEL                                                    */
#define MC_CPCTRL_CASEL_0                      0U      /* 0 : Fixed-priority arbitration                                     */
#define MC_CPCTRL_CASEL_1                      1U      /* 1 : Round-robin arbitration                                        */


/* ==============================================  MC CPCTRL SHAPCFG [24..25]  =============================================== */
                                 /* MC_CPCTRL_SHAPCFG                                                  */
#define MC_CPCTRL_SHAPCFG_00                   0U      /* 00 : Round robin                                                   */
#define MC_CPCTRL_SHAPCFG_01                   1U      /* 01 : Special round robin (favors SRAM backdoor accesses over
                                                     the processor)                                                     */
#define MC_CPCTRL_SHAPCFG_10                   2U      /* 10 : Fixed priority. Processor has highest  backdoor has lowest    */
#define MC_CPCTRL_SHAPCFG_11                   3U      /* 11 : Fixed priority. Backdoor has highest  processor has lowest    */


/* ==============================================  MC CPCTRL SLAPCFG [28..29]  =============================================== */
                                  /* MC_CPCTRL_SLAPCFG                                                  */
#define MC_CPCTRL_SLAPCFG_00                   0U      /* 00 : Round robin                                                   */
#define MC_CPCTRL_SLAPCFG_01                   1U      /* 01 : Special round robin (favors SRAM backdoor accesses over
                                                     the processor)                                                     */
#define MC_CPCTRL_SLAPCFG_10                   2U      /* 10 : Fixed priority. Processor has highest  backdoor has lowest    */
#define MC_CPCTRL_SLAPCFG_11                   3U      /* 11 : Fixed priority. Backdoor has highest  processor has lowest    */


